const getDaysView = `-- name: GetDaysView :many
WITH days AS (
    SELECT generate_series(
        CURRENT_DATE - ($2::INT - 1),
        CURRENT_DATE,
        interval '1 day'
    )::date AS day
)

SELECT
    d.day AS date,
    COALESCE(bm.views, 0) AS views

FROM days d

LEFT JOIN blogs.blog_metrics bm
    ON bm.blog_id = $1
   AND bm.date = d.day

ORDER BY d.day DESC
`

