const updateBlogRankingResult = `-- name: UpdateBlogRankingResult :exec
WITH comment_stats AS (
    SELECT
        c.blog_id,
        COUNT(*) AS comment_count
    FROM blogs.comments c
    GROUP BY c.blog_id
),
weekly_metrics AS (
    SELECT
        bm.blog_id,

        date_trunc('week', bm.date)::date AS week_start,

        SUM(bm.views) AS weekly_views

    FROM blogs.blog_metrics bm
    WHERE bm.date >= date_trunc('week', CURRENT_DATE) - interval '4 weeks'
    GROUP BY bm.blog_id, week_start
),

averaged_metrics AS (
    SELECT
        blog_id,

        ROUND(AVG(weekly_views)) AS weekly_access_count

    FROM weekly_metrics
    GROUP BY blog_id
),
base AS (
    SELECT
        b.blog_id,
        b.created_at,

        CASE
            WHEN COALESCE(am.weekly_access_count, 0) > 0
            THEN GREATEST(1, ROUND(am.weekly_access_count / 7.0))
            ELSE 0
        END AS daily_access_count,

        COALESCE(am.weekly_access_count, 0) AS weekly_access_count,

        b.like_count,
        b.dislike_count,
        COALESCE(cs.comment_count, 0) AS comment_count,

        (
            -- daily
            (
                CASE
                    WHEN COALESCE(am.weekly_access_count, 0) > 0
                    THEN GREATEST(1, ROUND(am.weekly_access_count / 7.0))
                    ELSE 0
                END
            ) * 2 +

            -- weekly
            COALESCE(am.weekly_access_count, 0) * 1 +

            -- likes/dislikes
            (b.like_count + 0.25 * b.dislike_count) * 2 +

            -- sentiment
            (b.like_count - b.dislike_count) * 1 +

            -- comments
            COALESCE(cs.comment_count, 0) * 2

        ) AS base_score,

        EXTRACT(EPOCH FROM (NOW() - b.created_at)) / 3600 AS hours_since_created

    FROM blogs.blogs b

    LEFT JOIN averaged_metrics am
        ON am.blog_id = b.blog_id

    LEFT JOIN comment_stats cs
        ON cs.blog_id = b.blog_id

    WHERE b.status = 'active'
),
scored AS (
    SELECT
        blog_id, created_at, daily_access_count, weekly_access_count, like_count, dislike_count, comment_count, base_score, hours_since_created,
        base_score AS score_all_time,
        base_score / (1 + hours_since_created) AS score_trending
    FROM base
),
ranked AS (
    SELECT
        blog_id, created_at, daily_access_count, weekly_access_count, like_count, dislike_count, comment_count, base_score, hours_since_created, score_all_time, score_trending,
        RANK() OVER (ORDER BY score_all_time DESC) AS rank_all_time,
        RANK() OVER (ORDER BY score_trending DESC) AS rank_trending
    FROM scored
)
INSERT INTO blogs.blog_ranking (
    blog_id,
    rank_all_time,
    rank_trending,
    score_all_time,
    score_trending,
    like_count,
    dislike_count,
    comment_count,
    weekly_access_count,
    daily_access_count,
    created_at,
    computed_at
)
SELECT
    blog_id,

    -- only keep rank if in top 20
    CASE WHEN rank_all_time <= 20 THEN rank_all_time ELSE NULL END,
    CASE WHEN rank_trending <= 20 THEN rank_trending ELSE NULL END,

    score_all_time,
    score_trending,
    like_count,
    dislike_count,
    comment_count,
    weekly_access_count,
    daily_access_count,
    created_at,
    NOW()

FROM ranked
WHERE rank_all_time <= 20
   OR rank_trending <= 20
`

func (q *Queries) UpdateBlogRankingResult(ctx context.Context) error {
	_, err := q.db.Exec(ctx, updateBlogRankingResult)
	return err
}

