const updateComment = `-- name: UpdateComment :one
UPDATE blogs.comments
SET
    -- wipe data on status deleted
    content = CASE
        WHEN COALESCE($3, status) = 'deleted'
             AND status <> 'deleted'
        THEN 'deleted by user'
        ELSE COALESCE($4, content)
    END,
    -- wipe data on status deleted
    actor_display_name = CASE
        WHEN COALESCE($3, status) = 'deleted'
             AND status <> 'deleted'
        THEN 'deleted by user'
        ELSE actor_display_name
    END,
    actor_id= CASE
        WHEN COALESCE($3, status) = 'deleted'
             AND status <> 'deleted'
        THEN NULL
        ELSE actor_id
    END,
    actor_avatar_url= CASE
        WHEN COALESCE($3, status) = 'deleted'
             AND status <> 'deleted'
        THEN NULL
        ELSE actor_avatar_url
    END,
    updated_at = NOW(),
    deleted_at = CASE
        WHEN COALESCE($3, status) = 'deleted'
             AND status <> 'deleted'
        THEN NOW()
        WHEN COALESCE($3, status) <> 'deleted'
        THEN NULL
        ELSE deleted_at
    END
WHERE id = $1 AND (actor_id = $2 OR $5::BOOLEAN = TRUE)
RETURNING id
`

type UpdateCommentParams struct {
	ID      uuid.UUID
	ActorID pgtype.Text
	Status  pgtype.Text
	Content pgtype.Text
	IsAdmin bool
}

func (q *Queries) UpdateComment(ctx context.Context, arg UpdateCommentParams) (uuid.UUID, error) {
	row := q.db.QueryRow(ctx, updateComment,
		arg.ID,
		arg.ActorID,
		arg.Status,
		arg.Content,
		arg.IsAdmin,
	)
	var id uuid.UUID
	err := row.Scan(&id)
	return id, err
}

